import pytest
import requests
import copy

BASE_URL = "http://fhir-lite/api"

@pytest.fixture
def clinician_headers():
    return <fixture:clinician_auth_headers>

@pytest.fixture
def base_payload():
    return <fixture:valid_referral_payload_with_consent>

@pytest.mark.parametrize("priority,expected_status", [
    (0,   201),
    (100, 201),
    (-1,  422),
    (101, 422),
])
def test_referral_boundary_priority_values(
    clinician_headers, base_payload, priority, expected_status
):
    payload = copy.deepcopy(base_payload)
    payload["priority"] = priority
    resp = requests.post(
        f"{BASE_URL}/ReferralRequest",
        json=payload,
        headers=clinician_headers,
    )
    assert resp.status_code == expected_status, (
        f"priority={priority}: expected {expected_status}, got {resp.status_code}"
    )

def test_referral_boundary_max_timestamp(clinician_headers, base_payload):
    payload = copy.deepcopy(base_payload)
    payload["authoredOn"] = "9999-12-31T23:59:59Z"
    resp = requests.post(
        f"{BASE_URL}/ReferralRequest",
        json=payload,
        headers=clinician_headers,
    )
    assert resp.status_code in (201, 422), (
        f"Max timestamp must yield 201 or 422, got {resp.status_code}"
    )
    if resp.status_code == 422:
        assert "authoredOn" in resp.text, "Validation error must reference authoredOn field"
